using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder — happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = CreateItems(("Widget", 25.50m, 3));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(76.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalAcrossAllItems()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 4));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert — (10*2) + (5*4) = 40
        Assert.AreEqual(40m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_Always_AssignsNonEmptyId()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_Always_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsInRange(order.CreatedAt, before, after);
    }

    [TestMethod]
    public void CreateOrder_WithItems_StoresItemsOnOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1), ("Gadget", 5m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.HasCount(2, order.Items);
    }

    #endregion

    #region CreateOrder — validation

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(() => _service.CreateOrder("cust-1", items));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        // Act
        var result = _service.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        // Act
        var orders = _service.GetOrdersByCustomer("cust-none");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMultipleOrders_ReturnsAllMatchingOrders()
    {
        // Arrange
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 3m, 1)));

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomersOrders()
    {
        // Arrange
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        var otherOrder = _service.CreateOrder("cust-2", CreateItems(("B", 2m, 1)));

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.DoesNotContain(otherOrder, orders);
    }

    #endregion

    #region Data-driven total calculation

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_CalculatesExpectedTotal(string description, decimal price, int qty, decimal expectedTotal)
    {
        // Arrange
        var items = CreateItems((description, price, qty));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<(string description, decimal price, int qty, decimal expectedTotal)> TotalCalculationData =>
    [
        ("Single unit", 15.00m, 1, 15.00m),
        ("Multiple units", 7.50m, 4, 30.00m),
        ("Zero price", 0m, 5, 0m),
    ];

    #endregion
}

